INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-10ced7e2-moex-00386', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '有關原住民族綜合發展基金之敘述，下列何者錯誤？', '["原住民族綜合發展基金由政府設立，辦理原住民族經濟發展業務、輔導事業機構、住宅之興辦、租 售、建購及修繕業務", "基金之法定來源包括原住民族地區溫泉取用費提撥款", "基金之法定用途包括原住民族就學基金支出", "原住民族綜合發展基金管理會召集人，為原住民族委員會副主任委員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00387', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '依據原住民族傳統智慧創作保護條例，經認定為智慧創作者，依法取得智慧創作專用權之敘述，何者 錯誤？', '["智慧創作經認定屬於申請人者，應准予登記，並自登記之日起，由申請人取得智慧創作專用權", "智慧創作經認定屬於申請人及其他特定原住民族或部落者，自登記之日起，由申請人及其他特定原 住民族或部落共同取得智慧創作專用權", "智慧創作不能認定屬於特定原住民族或部落者，應登記為公共所有，並自登記之日起，由全民取得 智慧創作專用權", "智慧創作專用權人之名稱有變更者，應申請變更登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00388', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '依據原住民族工作權保障法處理原住民勞資爭議時，下列敘述何者正確？', '["原住民勞資爭議，應依據勞資爭議處理法規定辦理", "勞資權利事項與調整事項之爭議，勞方當事人有二分之一以上為原住民時，關於調解委員或仲裁委 員有特別規定", "原住民在工作職場發生就業歧視或勞資糾紛，各級主管機關應予以法律諮詢、提供律師及全額訴訟 費之扶助", "直轄市、縣（市）政府依據勞資爭議處理法第30條規定推薦核備之仲裁委員名單中，應至少1人 至3人為具有原住民身分者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00389', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '關於原住民族實驗教育，下列敘述何者錯誤？', '["教育主管機關為發展原住民族教育，得指定所屬公立高級中等以下學校，或由學校提出申請，辦理 部分班級實驗教育", "國民小學、國民中學辦理原民實驗教育，其課程應依國民小學課程綱要規劃之", "學校辦理原民實驗教育，實驗前徵得學生本人及其法定代理人之同意。但學生已成年者，免經法定 代理人同意", "學校得依經核准之實驗計畫需要，以契約進用教學及工作人員"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00390', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '關於原住民幼兒教保服務，下列敘述何者錯誤？', '["原住民幼兒申請就讀公立幼兒園、非營利幼兒園、社區或部落互助教保服務中心時，有優先權", "部落互助教保服務中心，其招收具原住民身分之幼兒及二親等內任一直系血親具原住民身分之幼 兒，合計應達招收幼兒總人數百分之八十以上", "部落互助教保服務中心，依法有必要且經報直轄市、縣（市）教育及原住民族主管機關會同核准者， 其專任之幼兒園教師、教保員或助理教保員，以經原住民族族語認證且具高級中等學校以上學歷者 替代之", "部落互助教保服務中心專任之幼兒園教師、教保員或助理教保員，得以經原住民族族語認證且具高 級中等學校以上學歷者，全數替代之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00391', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '依據原住民民族別認定辦法，下列敘述何者錯誤？', '["父母均為原住民，且屬於相同民族別者，其子女之民族別從之", "父母均為原住民，且屬於不同民族別者，其子女從父之民族別", "父母僅一方為原住民，具有原住民身分之子女，從具原住民身分之父或母之民族別", "因收養而取得原住民身分之養子女，養父母屬於不同民族別者，其養子女從養父或養母之民族別"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00392', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '依據原住民族基本法第21條和諮商取得原住民族部落同意參與辦法，下列敘述何者錯誤？', '["政府或私人於原住民族土地或部落及其周邊一定範圍內之公有土地從事土地開發、資源利用、生態 保育及學術研究時，適用原住民族基本法第21條和諮商取得原住民族部落同意參與辦法", "部落會議職權包括訂定部落章程", "部落章程、部落會議所為決議及部落幹部所為決定之內容違反法令者，無效", "部落會議議決同意事項，以部落全體原住民家戶代表過半數出席，出席原住民家戶代表超過三分之 二贊成，為通過"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00393', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '依據地方制度法，有關直轄市山地原住民區，下列敘述何者錯誤？', '["直轄市山地原住民區屬地方自治團體", "區民代表會為其立法機關", "自治事項包括該區國民教育學校之設立", "自治事項包括該區之公用及公營事業"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00394', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '依據中華民國憲法增修條文之規定，下列何者錯誤？', '["立法院立法委員應選出平地原住民及山地原住民各3人", "國家應對原住民族其就學、就業、就醫、就養予以保障", "國家肯定多元文化，並積極維護發展原住民族語言及文化", "國家應依民族意願，保障原住民族之地位及政治參與，並對其教育文化、交通水利、衛生醫療、經 濟土地及社會福利事業予以保障扶助並促其發展"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00395', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '關於保障原住民族司法權益，下列敘述何者錯誤？', '["依據原住民族基本法，政府為保障原住民族之司法權益，得設置原住民族法院或法庭", "現行原住民專業法庭審理案件範圍，為刑事案件與民事案件", "目前原告或被告為原住民之刑事案件，不論何種犯罪類型，均由原住民族專業法庭（股）審理", "花蓮地方法院設有原住民族專業法庭（股）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL)
